#!/usr/bin/env python3
"""
Kafka Cluster Administration Script

Provides topic creation, partition management, and topic configuration
using kafka-python AdminClient.

Usage examples:
    # Create a topic with default settings
    python solution.py create --topic my-topic

    # Create a topic with custom partitions and replication
    python solution.py create --topic my-topic --partitions 6 --replication-factor 3

    # Create a topic with custom configuration
    python solution.py create --topic my-topic --partitions 3 --config retention.ms=86400000 --config cleanup.policy=compact

    # List all topics
    python solution.py list

    # Describe a topic
    python solution.py describe --topic my-topic

    # Delete a topic
    python solution.py delete --topic my-topic

    # Add partitions to a topic
    python solution.py add-partitions --topic my-topic --partitions 10

    # Alter topic configuration
    python solution.py alter-config --topic my-topic --config retention.ms=172800000 --config max.message.bytes=2097152

    # Describe topic configuration
    python solution.py describe-config --topic my-topic

    # Bulk create topics from a JSON file
    python solution.py bulk-create --file topics.json

    # Check cluster health
    python solution.py health
"""

import argparse
import json
import sys
import time
import logging
from typing import Dict, List, Optional, Any

try:
    from kafka import KafkaAdminClient, KafkaConsumer
    from kafka.admin import (
        NewTopic,
        NewPartitions,
        ConfigResource,
        ConfigResourceType,
    )
    from kafka.errors import (
        TopicAlreadyExistsError,
        UnknownTopicOrPartitionError,
        KafkaError,
        InvalidReplicationFactorError,
        InvalidPartitionsError,
    )
except ImportError:
    print("Error: kafka-python is required. Install it with: pip install kafka-python")
    sys.exit(1)


logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s - %(name)s - %(levelname)s - %(message)s",
)
logger = logging.getLogger("kafka-admin")


class KafkaClusterAdmin:
    """Manages Kafka cluster administration tasks."""

    def __init__(
        self,
        bootstrap_servers: str = "localhost:9092",
        client_id: str = "kafka-admin-tool",
        security_protocol: str = "PLAINTEXT",
        sasl_mechanism: Optional[str] = None,
        sasl_plain_username: Optional[str] = None,
        sasl_plain_password: Optional[str] = None,
        ssl_cafile: Optional[str] = None,
        ssl_certfile: Optional[str] = None,
        ssl_keyfile: Optional[str] = None,
        request_timeout_ms: int = 30000,
    ):
        """Initialize the Kafka admin client with connection parameters."""
        self.bootstrap_servers = bootstrap_servers
        self.config = {
            "bootstrap_servers": bootstrap_servers.split(","),
            "client_id": client_id,
            "security_protocol": security_protocol,
            "request_timeout_ms": request_timeout_ms,
        }

        if sasl_mechanism:
            self.config["sasl_mechanism"] = sasl_mechanism
        if sasl_plain_username:
            self.config["sasl_plain_username"] = sasl_plain_username
        if sasl_plain_password:
            self.config["sasl_plain_password"] = sasl_plain_password
        if ssl_cafile:
            self.config["ssl_cafile"] = ssl_cafile
        if ssl_certfile:
            self.config["ssl_certfile"] = ssl_certfile
        if ssl_keyfile:
            self.config["ssl_keyfile"] = ssl_keyfile

        self.admin_client = None
        self._connect()

    def _connect(self):
        """Establish connection to Kafka cluster."""
        try:
            self.admin_client = KafkaAdminClient(**self.config)
            logger.info(f"Connected to Kafka cluster at {self.bootstrap_servers}")
        except KafkaError as e:
            logger.error(f"Failed to connect to Kafka cluster: {e}")
            raise

    def close(self):
        """Close the admin client connection."""
        if self.admin_client:
            self.admin_client.close()
            logger.info("Disconnected from Kafka cluster")

    def create_topic(
        self,
        topic_name: str,
        num_partitions: int = 1,
        replication_factor: int = 1,
        topic_configs: Optional[Dict[str, str]] = None,
    ) -> bool:
        """Create a new Kafka topic."""
        try:
            new_topic = NewTopic(
                name=topic_name,
                num_partitions=num_partitions,
                replication_factor=replication_factor,
                topic_configs=topic_configs or {},
            )
            result = self.admin_client.create_topics(
                new_topics=[new_topic], validate_only=False
            )
            logger.info(
                f"Topic '{topic_name}' created successfully "
                f"(partitions={num_partitions}, replication_factor={replication_factor})"
            )
            if topic_configs:
                logger.info(f"  Configuration: {topic_configs}")
            return True
        except TopicAlreadyExistsError:
            logger.warning(f"Topic '{topic_name}' already exists")
            return False
        except InvalidReplicationFactorError as e:
            logger.error(
                f"Invalid replication factor for topic '{topic_name}': {e}"
            )
            return False
        except InvalidPartitionsError as e:
            logger.error(f"Invalid partitions for topic '{topic_name}': {e}")
            return False
        except KafkaError as e:
            logger.error(f"Failed to create topic '{topic_name}': {e}")
            return False

    def bulk_create_topics(self, topics_config: List[Dict[str, Any]]) -> Dict[str, bool]:
        """Create multiple topics from a list of configurations."""
        results = {}
        for topic_conf in topics_config:
            topic_name = topic_conf.get("name")
            if not topic_name:
                logger.warning("Skipping topic config without 'name' field")
                continue

            success = self.create_topic(
                topic_name=topic_name,
                num_partitions=topic_conf.get("partitions", 1),
                replication_factor=topic_conf.get("replication_factor", 1),
                topic_configs=topic_conf.get("config", {}),
            )
            results[topic_name] = success
        return results

    def delete_topics(self, topic_names: List[str]) -> Dict[str, bool]:
        """Delete one or more Kafka topics."""
        results = {}
        for topic_name in topic_names:
            try:
                self.admin_client.delete_topics(topics=[topic_name])
                logger.info(f"Topic '{topic_name}' deleted successfully")
                results[topic_name] = True
            except UnknownTopicOrPartitionError:
                logger.warning(f"Topic '{topic_name}' does not exist")
                results[topic_name] = False
            except KafkaError as e:
                logger.error(f"Failed to delete topic '{topic_name}': {e}")
                results[topic_name] = False
        return results

    def list_topics(self) -> List[str]:
        """List all topics in the cluster."""
        try:
            topics = self.admin_client.list_topics()
            return sorted(topics)
        except KafkaError as e:
            logger.error(f"Failed to list topics: {e}")
            return []

    def describe_topics(self, topic_names: List[str]) -> Dict[str, Any]:
        """Describe one or more topics with detailed information."""
        results = {}
        try:
            descriptions = self.admin_client.describe_topics(topic_names)
            for desc in descriptions:
                topic_name = desc.get("topic", "unknown")
                partitions_info = []
                for partition in desc.get("partitions", []):
                    partition_data = {
                        "partition": partition.get("partition"),
                        "leader": partition.get("leader"),
                        "replicas": partition.get("replicas", []),
                        "isr": partition.get("isr", []),
                    }
                    partitions_info.append(partition_data)

                results[topic_name] = {
                    "topic": topic_name,
                    "partitions_count": len(partitions_info),
                    "partitions": partitions_info,
                    "is_internal": desc.get("is_internal", False),
                    "error_code": desc.get("error_code", 0),
                }
            return results
        except UnknownTopicOrPartitionError as e:
            logger.error(f"Topic not found: {e}")
            return {}
        except KafkaError as e:
            logger.error(f"Failed to describe topics: {e}")
            return {}

    def add_partitions(self, topic_name: str, total_partitions: int) -> bool:
        """Increase the number of partitions for a topic."""
        try:
            topic_descriptions = self.describe_topics([topic_name])
            if topic_name not in topic_descriptions:
                logger.error(f"Topic '{topic_name}' not found")
                return False

            current_partitions = topic_descriptions[topic_name]["partitions_count"]
            if total_partitions <= current_partitions:
                logger.error(
                    f"New partition count ({total_partitions}) must be greater than "
                    f"current count ({current_partitions})"
                )
                return False

            new_partitions = {topic_name: NewPartitions(total_count=total_partitions)}
            self.admin_client.create_partitions(new_partitions)
            logger.info(
                f"Partitions for topic '{topic_name}' increased from "
                f"{current_partitions} to {total_partitions}"
            )
            return True
        except InvalidPartitionsError as e:
            logger.error(f"Invalid partition configuration: {e}")
            return False
        except KafkaError as e:
            logger.error(f"Failed to add partitions to topic '{topic_name}': {e}")
            return False

    def describe_topic_config(self, topic_name: str) -> Dict[str, str]:
        """Get the configuration for a specific topic."""
        try:
            config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
            result = self.admin_client.describe_configs([config_resource])

            configs = {}
            for resource_result in result:
                for config_entry in result[resource_result].values():
                    configs[config_entry.name] = {
                        "value": config_entry.value,
                        "is_default": config_entry.is_default,
                        "is_read_only": config_entry.is_read_only,
                        "is_sensitive": config_entry.is_sensitive,
                    }
            return configs
        except UnknownTopicOrPartitionError:
            logger.error(f"Topic '{topic_name}' not found")
            return {}
        except KafkaError as e:
            logger.error(f"Failed to describe config for topic '{topic_name}': {e}")
            return {}

    def alter_topic_config(
        self, topic_name: str, configs: Dict[str, str]
    ) -> bool:
        """Alter the configuration for a specific topic."""
        try:
            config_resource = ConfigResource(
                ConfigResourceType.TOPIC,
                topic_name,
                configs=configs,
            )
            self.admin_client.alter_configs([config_resource])
            logger.info(
                f"Configuration for topic '{topic_name}' updated: {configs}"
            )
            return True
        except UnknownTopicOrPartitionError:
            logger.error(f"Topic '{topic_name}' not found")
            return False
        except KafkaError as e:
            logger.error(
                f"Failed to alter config for topic '{topic_name}': {e}"
            )
            return False

    def get_cluster_metadata(self) -> Dict[str, Any]:
        """Get cluster metadata including broker information."""
        try:
            consumer = KafkaConsumer(
                bootstrap_servers=self.bootstrap_servers.split(","),
                security_protocol=self.config.get("security_protocol", "PLAINTEXT"),
            )
            cluster = consumer.bootstrap_connected()
            topics = consumer.topics()
            partitions_info = {}
            for topic in topics:
                partitions = consumer.partitions_for_topic(topic)
                if partitions:
                    partitions_info[topic] = len(partitions)

            consumer.close()

            return {
                "connected": cluster,
                "topics_count": len(topics),
                "topics": sorted(topics),
                "partitions_per_topic": partitions_info,
            }
        except KafkaError as e:
            logger.error(f"Failed to get cluster metadata: {e}")
            return {}

    def check_cluster_health(self) -> Dict[str, Any]:
        """Perform a basic health check on the Kafka cluster."""
        health = {
            "status": "unknown",
            "bootstrap_servers": self.bootstrap_servers,
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
        }

        try:
            topics = self.list_topics()
            health["topics_count"] = len(topics)
            health["status"] = "healthy"
            health["topics"] = topics

            # Check for under-replicated partitions
            under_replicated = []
            for topic in topics:
                try:
                    desc = self.describe_topics([topic])
                    if topic in desc:
                        for partition in desc[topic].get("partitions", []):
                            replicas = partition.get("replicas", [])
                            isr = partition.get("isr", [])
                            if len(isr) < len(replicas):
                                under_replicated.append(
                                    {
                                        "topic": topic,
                                        "partition": partition.get("partition"),
                                        "replicas": len(replicas),
                                        "isr": len(isr),
                                    }
                                )
                except Exception:
                    pass

            health["under_replicated_partitions"] = under_replicated
            if under_replicated:
                health["status"] = "degraded"
                health["warnings"] = [
                    f"{len(under_replicated)} under-replicated partition(s) found"
                ]

        except KafkaError as e:
            health["status"] = "unhealthy"
            health["error"] = str(e)

        return health


def parse_config_args(config_list: Optional[List[str]]) -> Dict[str, str]:
    """Parse configuration arguments in key=value format."""
    configs = {}
    if config_list:
        for config_str in config_list:
            if "=" in config_str:
                key, value = config_str.split("=", 1)
                configs[key.strip()] = value.strip()
            else:
                logger.warning(f"Invalid config format '{config_str}', expected key=value")
    return configs


def format_output(data: Any, output_format: str = "text") -> str:
    """Format output data as text or JSON."""
    if output_format == "json":
        return json.dumps(data, indent=2, default=str)

    if isinstance(data, dict):
        lines = []
        for key, value in data.items():
            if isinstance(value, dict):
                lines.append(f"\n{key}:")
                for k, v in value.items():
                    lines.append(f"  {k}: {v}")
            elif isinstance(value, list):
                lines.append(f"\n{key}:")
                for item in value:
                    if isinstance(item, dict):
                        for k, v in item.items():
                            lines.append(f"    {k}: {v}")
                        lines.append("    ---")
                    else:
                        lines.append(f"  - {item}")
            else:
                lines.append(f"{key}: {value}")
        return "\n".join(lines)
    elif isinstance(data, list):
        return "\n".join(f"  - {item}" for item in data)
    return str(data)


def create_parser() -> argparse.ArgumentParser:
    """Create the argument parser with all subcommands."""
    parser = argparse.ArgumentParser(
        description="Kafka Cluster Administration Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s create --topic my-topic --partitions 3 --replication-factor 2
  %(prog)s create --topic my-topic --config retention.ms=86400000 --config cleanup.policy=compact
  %(prog)s list
  %(prog)s describe --topic my-topic
  %(prog)s delete --topic my-topic
  %(prog)s add-partitions --topic my-topic --partitions 10
  %(prog)s alter-config --topic my-topic --config retention.ms=172800000
  %(prog)s describe-config --topic my-topic
  %(prog)s bulk-create --file topics.json
  %(prog)s health
        """,
    )

    # Global arguments
    parser.add_argument(
        "--bootstrap-servers",
        default="localhost:9092",
        help="Kafka bootstrap servers (default: localhost:9092)",
    )
    parser.add_argument(
        "--security-protocol",
        default="PLAINTEXT",
        choices=["PLAINTEXT", "SSL", "SASL_PLAINTEXT", "SASL_SSL"],
        help="Security protocol (default: PLAINTEXT)",
    )
    parser.add_argument(
        "--sasl-mechanism",
        default=None,
        choices=["PLAIN", "GSSAPI", "SCRAM-SHA-256", "SCRAM-SHA-512"],
        help="SASL mechanism",
    )
    parser.add_argument("--sasl-username", default=None, help="SASL username")
    parser.add_argument("--sasl-password", default=None, help="SASL password")
    parser.add_argument("--ssl-cafile", default=None, help="SSL CA file path")
    parser.add_argument("--ssl-certfile", default=None, help="SSL certificate file path")
    parser.add_argument("--ssl-keyfile", default=None, help="SSL key file path")
    parser.add_argument(
        "--output",
        "-o",
        default="text",
        choices=["text", "json"],
        help="Output format (default: text)",
    )
    parser.add_argument(
        "--verbose", "-v", action="store_true", help="Enable verbose logging"
    )
    parser.add_argument(
        "--timeout",
        type=int,
        default=30000,
        help="Request timeout in milliseconds (default: 30000)",
    )

    subparsers = parser.add_subparsers(dest="command", help="Available commands")

    # Create topic
    create_parser = subparsers.add_parser("create", help="Create a new topic")
    create_parser.add_argument("--topic", "-t", required=True, help="Topic name")
    create_parser.add_argument(
        "--partitions", "-p", type=int, default=1, help="Number of partitions (default: 1)"
    )
    create_parser.add_argument(
        "--replication-factor",
        "-r",
        type=int,
        default=1,
        help="Replication factor (default: 1)",
    )
    create_parser.add_argument(
        "--config",
        "-c",
        action="append",
        help="Topic configuration in key=value format (can be repeated)",
    )

    # List topics
    subparsers.add_parser("list", help="List all topics")

    # Describe topic
    describe_parser = subparsers.add_parser("describe", help="Describe a topic")
    describe_parser.add_argument(
        "--topic", "-t", required=True, nargs="+", help="Topic name(s)"
    )

    # Delete topic
    delete_parser = subparsers.add_parser("delete", help="Delete a topic")
    delete_parser.add_argument(
        "--topic", "-t", required=True, nargs="+", help="Topic name(s) to delete"
    )
    delete_parser.add_argument(
        "--force", "-f", action="store_true", help="Skip confirmation"
    )

    # Add partitions
    partitions_parser = subparsers.add_parser(
        "add-partitions", help="Add partitions to a topic"
    )
    partitions_parser.add_argument("--topic", "-t", required=True, help="Topic name")
    partitions_parser.add_argument(
        "--partitions",
        "-p",
        type=int,
        required=True,
        help="New total number of partitions",
    )

    # Alter topic configuration
    alter_config_parser = subparsers.add_parser(
        "alter-config", help="Alter topic configuration"
    )
    alter_config_parser.add_argument("--topic", "-t", required=True, help="Topic name")
    alter_config_parser.add_argument(
        "--config",
        "-c",
        action="append",
        required=True,
        help="Configuration in key=value format (can be repeated)",
    )

    # Describe topic configuration
    desc_config_parser = subparsers.add_parser(
        "describe-config", help="Describe topic configuration"
    )
    desc_config_parser.add_argument("--topic", "-t", required=True, help="Topic name")
    desc_config_parser.add_argument(
        "--non-default-only",
        action="store_true",
        help="Show only non-default configurations",
    )

    # Bulk create topics
    bulk_parser = subparsers.add_parser(
        "bulk-create", help="Bulk create topics from a JSON file"
    )
    bulk_parser.add_argument(
        "--file", "-f", required=True, help="JSON file with topic configurations"
    )

    # Health check
    subparsers.add_parser("health", help="Check cluster health")

    return parser


def main():
    """Main entry point for the Kafka admin tool."""
    parser = create_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    try:
        admin = KafkaClusterAdmin(
            bootstrap_servers=args.bootstrap_servers,
            security_protocol=args.security_protocol,
            sasl_mechanism=args.sasl_mechanism,
            sasl_plain_username=args.sasl_username,
            sasl_plain_password=args.sasl_password,
            ssl_cafile=args.ssl_cafile,
            ssl_certfile=args.ssl_certfile,
            ssl_keyfile=args.ssl_keyfile,
            request_timeout_ms=args.timeout,
        )
    except Exception as e:
        logger.error(f"Failed to initialize Kafka admin client: {e}")
        sys.exit(1)

    try:
        if args.command == "create":
            configs = parse_config_args(args.config)
            success = admin.create_topic(
                topic_name=args.topic,
                num_partitions=args.partitions,
                replication_factor=args.replication_factor,
                topic_configs=configs,
            )
            if success:
                result = {
                    "action": "create",
                    "topic": args.topic,
                    "partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "config": configs,
                    "status": "created",
                }
            else:
                result = {
                    "action": "create",
                    "topic": args.topic,
                    "status": "failed_or_exists",
                }
            print(format_output(result, args.output))

        elif args.command == "list":
            topics = admin.list_topics()
            if args.output == "json":
                print(json.dumps({"topics": topics, "count": len(topics)}, indent=2))
            else:
                print(f"Topics ({len(topics)}):")
                for topic in topics:
                    print(f"  - {topic}")

        elif args.command == "describe":
            descriptions = admin.describe_topics(args.topic)
            if args.output == "json":
                print(json.dumps(descriptions, indent=2, default=str))
            else:
                for topic_name, info in descriptions.items():
                    print(f"\nTopic: {topic_name}")
                    print(f"  Internal: {info.get('is_internal', False)}")
                    print(f"  Partitions: {info.get('partitions_count', 0)}")
                    for partition in info.get("partitions", []):
                        print(f"    Partition {partition['partition']}:")
                        print(f"      Leader: {partition['leader']}")
                        print(f"      Replicas: {partition['replicas']}")
                        print(f"      ISR: {partition['isr']}")

        elif args.command == "delete":
            if not args.force:
                topics_str = ", ".join(args.topic)
                confirm = input(
                    f"Are you sure you want to delete topic(s): {topics_str}? [y/N]: "
                )
                if confirm.lower() != "y":
                    print("Deletion cancelled.")
                    sys.exit(0)

            results = admin.delete_topics(args.topic)
            if args.output == "json":
                print(json.dumps({"deleted": results}, indent=2))
            else:
                for topic, success in results.items():
                    status = "deleted" if success else "failed"
                    print(f"  {topic}: {status}")

        elif args.command == "add-partitions":
            success = admin.add_partitions(args.topic, args.partitions)
            result = {
                "action": "add-partitions",
                "topic": args.topic,
                "new_total_partitions": args.partitions,
                "status": "success" if success else "failed",
            }
            print(format_output(result, args.output))

        elif args.command == "alter-config":
            configs = parse_config_args(args.config)
            if not configs:
                logger.error("No valid configurations provided")
                sys.exit(1)

            success = admin.alter_topic_config(args.topic, configs)
            result = {
                "action": "alter-config",
                "topic": args.topic,
                "configs": configs,
                "status": "success" if success else "failed",
            }
            print(format_output(result, args.output))

        elif args.command == "describe-config":
            configs = admin.describe_topic_config(args.topic)
            if hasattr(args, "non_default_only") and args.non_default_only:
                configs = {
                    k: v for k, v in configs.items() if not v.get("is_default", True)
                }

            if args.output == "json":
                print(
                    json.dumps(
                        {"topic": args.topic, "configs": configs}, indent=2, default=str
                    )
                )
            else:
                print(f"\nConfiguration for topic '{args.topic}':")
                print(f"{'Config':<45} {'Value':<30} {'Default':<10} {'ReadOnly':<10}")
                print("-" * 95)
                for name, details in sorted(configs.items()):
                    value = details.get("value", "N/A")
                    is_default = details.get("is_default", "N/A")
                    is_read_only = details.get("is_read_only", "N/A")
                    if value and len(str(value)) > 28:
                        value = str(value)[:25] + "..."
                    print(f"  {name:<43} {str(value):<30} {str(is_default):<10} {str(is_read_only):<10}")

        elif args.command == "bulk-create":
            try:
                with open(args.file, "r") as f:
                    topics_config = json.load(f)
            except FileNotFoundError:
                logger.error(f"File not found: {args.file}")
                sys.exit(1)
            except json.JSONDecodeError as e:
                logger.error(f"Invalid JSON in file '{args.file}': {e}")
                sys.exit(1)

            if isinstance(topics_config, dict) and "topics" in topics_config:
                topics_config = topics_config["topics"]

            if not isinstance(topics_config, list):
                logger.error("JSON file must contain a list of topic configurations or a dict with 'topics' key")
                sys.exit(1)

            results = admin.bulk_create_topics(topics_config)
            if args.output == "json":
                print(json.dumps({"results": results}, indent=2))
            else:
                print("\nBulk Create Results:")
                for topic, success in results.items():
                    status = "created" if success else "failed/exists"
                    print(f"  {topic}: {status}")

        elif args.command == "health":
            health = admin.check_cluster_health()
            if args.output == "json":
                print(json.dumps(health, indent=2, default=str))
            else:
                print("\nCluster Health Check:")
                print(f"  Status: {health.get('status', 'unknown')}")
                print(f"  Bootstrap Servers: {health.get('bootstrap_servers', 'N/A')}")
                print(f"  Timestamp: {health.get('timestamp', 'N/A')}")
                print(f"  Topics Count: {health.get('topics_count', 'N/A')}")

                under_replicated = health.get("under_replicated_partitions", [])
                if under_replicated:
                    print(f"\n  Under-replicated Partitions ({len(under_replicated)}):")
                    for ur in under_replicated:
                        print(
                            f"    Topic: {ur['topic']}, Partition: {ur['partition']}, "
                            f"Replicas: {ur['replicas']}, ISR: {ur['isr']}"
                        )
                else:
                    print("  Under-replicated Partitions: None")

                warnings = health.get("warnings", [])
                if warnings:
                    print("\n  Warnings:")
                    for warning in warnings:
                        print(f"    - {warning}")

                if health.get("error"):
                    print(f"\n  Error: {health['error']}")

        else:
            parser.print_help()

    except KeyboardInterrupt:
        print("\nOperation cancelled by user.")
        sys.exit(130)
    except Exception as e:
        logger.error(f"Unexpected error: {e}")
        if args.verbose:
            import traceback
            traceback.print_exc()
        sys.exit(1)
    finally:
        admin.close()


if __name__ == "__main__":
    main()